template.minimal:
-- CTE: readable, may recompute
WITH base AS (SELECT ... FROM orders)
SELECT * FROM base WHERE ...;

-- Subquery: inline, no reuse
SELECT * FROM (SELECT ... FROM orders) t WHERE ...;

-- Temp table: materialized, reusable
CREATE TEMP TABLE base AS SELECT ... FROM orders;
SELECT * FROM base WHERE ...;
DROP TABLE base;

template.realistic:
-- Decision guide: when to use each
-- Scenario 1: Readable CTE pipeline (moderate size, one-off query)
WITH base AS (SELECT o.*, c.region FROM orders o JOIN customers c ON o.customer_id = c.customer_id WHERE o.order_date >= CURRENT_DATE - INTERVAL '90 days')
SELECT region, COUNT(*) FROM base GROUP BY region;

-- Scenario 2: Subquery for small, one-time filter
SELECT * FROM orders WHERE order_id IN (SELECT order_id FROM order_items WHERE quantity > 10);

-- Scenario 3: Temp table for reuse across multiple queries
CREATE TEMP TABLE top_customers AS (
  SELECT customer_id, SUM(oi.quantity * oi.unit_price) AS lifetime_revenue
  FROM orders o
  JOIN order_items oi ON o.order_id = oi.order_id
  GROUP BY customer_id
  HAVING SUM(oi.quantity * oi.unit_price) > 10000
);

-- Reuse top_customers in multiple downstream queries
SELECT * FROM top_customers WHERE region = 'North';
SELECT customer_id, COUNT(*) FROM top_customers JOIN orders USING (customer_id) GROUP BY 1;

template.composable:
-- CTE for readability + temp table for reuse in complex pipeline
-- Composes: cte_vs_subquery + cte_multi_stage_pipeline
WITH base_orders AS (
  SELECT o.*, c.region
  FROM orders o
  JOIN customers c ON o.customer_id = c.customer_id
  WHERE o.order_date >= CURRENT_DATE - INTERVAL '60 days'
),
 enriched AS (
   SELECT bo.*, (SELECT SUM(oi.quantity * oi.unit_price) FROM order_items oi WHERE oi.order_id = bo.order_id) AS revenue
   FROM base_orders bo
 )
CREATE TEMP TABLE enriched_orders AS SELECT * FROM enriched;

-- Now reuse in downstream queries
SELECT region, SUM(revenue) FROM enriched_orders GROUP BY region;
SELECT * FROM enriched_orders WHERE revenue > 1000 ORDER BY revenue DESC;

